class Solution:
    def splitArray(self, nums, k):
        # independent: dynamic programming over prefix sums.
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + nums[i]
        INF = float('inf')
        # dp[i][j] = min over splits of first i elements into j parts of the max part
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            for j in range(1, min(i, k) + 1):
                for p in range(j - 1, i):
                    seg = pre[i] - pre[p]
                    cand = max(dp[p][j - 1], seg)
                    if cand < dp[i][j]:
                        dp[i][j] = cand
        return dp[n][k]

