class Solution:
    def splitArray(self, nums, k):
        def segments(cap):
            count = 1
            cur = 0
            for x in nums:
                if cur + x > cap:
                    count += 1
                    cur = x
                else:
                    cur += x
            return count
        lo, hi = max(nums), sum(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if segments(mid) <= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

