var splitArray = function(nums, k) {
    const segments = (cap) => {
        let count = 1, cur = 0;
        for (const x of nums) {
            if (cur + x > cap) { count++; cur = x; }
            else cur += x;
        }
        return count;
    };
    let lo = Math.max(...nums);
    let hi = nums.reduce((a, b) => a + b, 0);
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (segments(mid) <= k) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
